import{_ as r,o,c as l,a2 as i}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"🫘 黃豆追蹤日報 — 2026-05-14（週四）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-14.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-14.md"}'),a={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-14.md"};function n(s,t,e,d,g,h){return o(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="🫘-黃豆追蹤日報-—-2026-05-14-週四" tabindex="-1">🫘 黃豆追蹤日報 — 2026-05-14（週四） <a class="header-anchor" href="#🫘-黃豆追蹤日報-—-2026-05-14-週四" aria-label="Permalink to &quot;🫘 黃豆追蹤日報 — 2026-05-14（週四）&quot;">​</a></h1><blockquote><p>查詢時間：2026-05-14 05:00 TST（2026-05-13 21:00 UTC） 報告類型：每日追蹤 ⚠️ CBOT 期貨時段說明：05:00 TST 週四凌晨 = 17:00 ET 週三，黃豆期貨處於 14:00-20:00 ET 休息時段</p></blockquote><hr><h2 id="📊-即時報價" tabindex="-1">📊 即時報價 <a class="header-anchor" href="#📊-即時報價" aria-label="Permalink to &quot;📊 即時報價&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>報價</th><th>日漲跌</th><th>查詢時間</th><th>來源</th></tr></thead><tbody><tr><td>CBOT 黃豆 Jul 2026 (ZS=F)</td><td>1,229.25¢/蒲式耳</td><td>+2.50 (+0.20%)</td><td>2026-05-13 18:34 ET</td><td>Yahoo Finance</td></tr><tr><td>CBOT 黃豆 May 2026 (ZSK26)</td><td>1,221.25¢</td><td>+7.75 (+0.64%)</td><td>2026-05-13 13:37 ET</td><td>Yahoo Finance</td></tr><tr><td>CBOT 黃豆 May 2027 (ZSK27)</td><td>1,216.75¢</td><td>+2.50 (+0.21%)</td><td>2026-05-13 07:53 ET</td><td>Yahoo Finance</td></tr><tr><td>WTI 原油</td><td>$102.18/桶</td><td>+4.2%</td><td>2026-05-13</td><td>Yahoo Finance</td></tr><tr><td>Brent 原油</td><td>$107.77/桶</td><td>+3.4%</td><td>2026-05-13</td><td>Yahoo Finance</td></tr><tr><td>DCE 黃豆 7月</td><td>4,804 元/噸</td><td>—</td><td>2026-05-08</td><td>SunSirs</td></tr><tr><td>Henry Hub 天然氣</td><td>~$2.92/MMBtu</td><td>+5.78%</td><td>2026-05-11</td><td>TradingEconomics</td></tr></tbody></table><blockquote><p><strong>查詢時間（TST）</strong>：2026-05-14 05:00</p></blockquote><hr><h2 id="🔍-敘事延續-wasde-26-27-年終庫存-310m-bu-川習會-300-億管理貿易" tabindex="-1">🔍 敘事延續：WASDE 26/27 年終庫存 310M bu + 川習會 $300 億管理貿易 <a class="header-anchor" href="#🔍-敘事延續-wasde-26-27-年終庫存-310m-bu-川習會-300-億管理貿易" aria-label="Permalink to &quot;🔍 敘事延續：WASDE 26/27 年終庫存 310M bu + 川習會 $300 億管理貿易&quot;">​</a></h2><p><strong>本日核心</strong>：USDA 5/12 WASDE 首次公布 2026/27 年度預估，年終庫存 310M 蒲式耳（低於預期），黃豆價格升至 2 年新高。同時，川習會今日在北京登場，路透社報導雙方將討論對 $300 億商品削減關稅，美國農民密切關注黃豆出口能否重啟。</p><hr><h2 id="_8-項追蹤指標" tabindex="-1">8 項追蹤指標 <a class="header-anchor" href="#_8-項追蹤指標" aria-label="Permalink to &quot;8 項追蹤指標&quot;">​</a></h2><h3 id="_1-usda-種植進度報告-每週" tabindex="-1">1. USDA 種植進度報告（每週） <a class="header-anchor" href="#_1-usda-種植進度報告-每週" aria-label="Permalink to &quot;1. USDA 種植進度報告（每週）&quot;">​</a></h3><ul><li><strong>最新數據</strong>：5/12 USDA WASDE 公布首次 2026/27 年度官方預估</li><li><strong>種植進度</strong>（截至 5/10）：49% 黃豆已播種（前週 33%），高於五年均值 36%，高於 2025 年同期 45%</li><li><strong>出芽率</strong>：20% 已出芽（五年均值 12%，2025 年 16%）</li><li><strong>2026/27 終庫存</strong>：310M 蒲式耳（低於 25/26 的 340M，低於分析師預期的 ~355M）</li><li><strong>2026/27 出口</strong>：1.63B 蒲式耳（+100M vs 25/26 的 1.53B，13 年低點回升）</li><li><strong>2026/27 壓榨</strong>：2.75B 蒲式耳（連續第 6 年創紀錄）</li><li><strong>變化</strong>：🟢 <strong>重大變化</strong> — 種植進度快 + WASDE 庫存低於預期 = 利多</li><li><strong>查詢時間</strong>：2026-05-12 12:00 ET / 2026-05-10 截止</li><li>來源：Farm Progress (2026-05-12)、Successful Farming (2026-05-11)、AgWeb (2026-05-12)</li></ul><h3 id="_2-巴西供應-收割-出口-豐收" tabindex="-1">2. 巴西供應（收割 + 出口 + 豐收） <a class="header-anchor" href="#_2-巴西供應-收割-出口-豐收" aria-label="Permalink to &quot;2. 巴西供應（收割 + 出口 + 豐收）&quot;">​</a></h3><ul><li><strong>巴西收割</strong>：2025/26 年度收割已基本完成</li><li><strong>巴西出口</strong>：持續強勁，中國需求在 2025 年大部分時間轉向巴西</li><li><strong>USDA 2026/27 全球</strong>：全球年終庫存 1.957B 蒲式耳（-185M vs 25/26，但 +35M vs 預期）</li><li><strong>變化</strong>：🟡 無重大變化 — 巴西供應穩定，但全球庫存下降趨勢明確</li><li><strong>查詢時間</strong>：2026-05-13</li><li>來源：USDA WASDE (2026-05-12)、Farm Progress (2026-05-12)</li></ul><h3 id="_3-尿素價格-多單訊號" tabindex="-1">3. 尿素價格 + 多單訊號 <a class="header-anchor" href="#_3-尿素價格-多單訊號" aria-label="Permalink to &quot;3. 尿素價格 + 多單訊號&quot;">​</a></h3><ul><li><strong>尿素</strong>：伊朗戰爭推升化肥成本（Investopedia 指出 PPI 飆升主因包括化肥價格上漲）</li><li><strong>變化</strong>：🟡 無重大變化 — 化肥成本持續高檔</li><li><strong>查詢時間</strong>：2026-05-13</li><li>來源：Investopedia (2026-05-13)</li></ul><h3 id="_4-荷莫茲海峽通航狀態" tabindex="-1">4. 荷莫茲海峽通航狀態 <a class="header-anchor" href="#_4-荷莫茲海峽通航狀態" aria-label="Permalink to &quot;4. 荷莫茲海峽通航狀態&quot;">​</a></h3><ul><li><strong>現狀</strong>：伊朗仍控制海峽，保留 30 個飛彈基地</li><li><strong>川普</strong>：稱停火「on life support」，拒絕伊朗最新提案</li><li><strong>IEA</strong>：全球石油供應將因伊朗戰爭減少 390 萬桶/日</li><li><strong>影響</strong>：航運成本上升 → 黃豆運輸成本增加</li><li><strong>變化</strong>：🔴 <strong>重大變化</strong> — IEA 警告供應缺口擴大，Hormuz 危機持續</li><li><strong>查詢時間</strong>：2026-05-13</li><li>來源：Reuters (2026-05-13)、Al Jazeera (2026-05-13)、ISW (2026-05-12)</li></ul><h3 id="_5-中美貿易-中國進口" tabindex="-1">5. 中美貿易 + 中國進口 <a class="header-anchor" href="#_5-中美貿易-中國進口" aria-label="Permalink to &quot;5. 中美貿易 + 中國進口&quot;">​</a></h3><ul><li><strong>川習會</strong>：今日在北京登場（5/14-15），路透社報導雙方將討論 $300 億管理貿易機制</li><li><strong>中國黃豆關稅</strong>：13%（10% 附加 + 3% MFN），農民期望此次峰會能重啟出口</li><li><strong>2025 年</strong>：中國幾乎 shut out 美國黃豆市場，農民損失慘重</li><li><strong>Farm Progress</strong>：若中國大量採購，黃豆期貨可能觸及 $14.80</li><li><strong>變化</strong>：🔴 <strong>重大變化</strong> — 川習會今日登場，黃豆出口前景存在突破可能</li><li><strong>查詢時間</strong>：2026-05-13</li><li>來源：Reuters (2026-05-13)、Farm Progress (2026-05-11)、AP (2026-05-13)</li></ul><h3 id="_6-天然氣價格" tabindex="-1">6. 天然氣價格 <a class="header-anchor" href="#_6-天然氣價格" aria-label="Permalink to &quot;6. 天然氣價格&quot;">​</a></h3><ul><li><strong>Henry Hub</strong>：~$2.92/MMBtu（+5.78%）</li><li><strong>變化</strong>：🟡 無重大變化 — 天然氣價格溫和上漲</li><li><strong>查詢時間</strong>：2026-05-11</li><li>來源：TradingEconomics (2026-05-11)</li></ul><h3 id="_7-聖嬰-拉尼娜氣候風險" tabindex="-1">7. 聖嬰/拉尼娜氣候風險 <a class="header-anchor" href="#_7-聖嬰-拉尼娜氣候風險" aria-label="Permalink to &quot;7. 聖嬰/拉尼娜氣候風險&quot;">​</a></h3><ul><li><strong>變化</strong>：⚪ 無即時更新 — 待季度更新</li><li><strong>查詢時間</strong>：2026-05-13</li></ul><h3 id="_8-cbot-價格區間" tabindex="-1">8. CBOT 價格區間 <a class="header-anchor" href="#_8-cbot-價格區間" aria-label="Permalink to &quot;8. CBOT 價格區間&quot;">​</a></h3><ul><li><strong>Jul 2026 (ZS=F)</strong>：1,229.25¢（+0.20%），2 年新高</li><li><strong>May 2026 (ZSK26)</strong>：1,221.25¢（+0.64%）</li><li><strong>May 2027 (ZSK27)</strong>：1,216.75¢（+0.21%）</li><li><strong>分析</strong>：WASDE 低於預期庫存 + 川習會樂觀預期 → 價格支撐</li><li><strong>變化</strong>：🟢 價格維持 2 年高點，市場等待川習會結果</li><li><strong>查詢時間</strong>：2026-05-13 18:34 ET</li><li>來源：Yahoo Finance (2026-05-13)</li></ul><hr><h2 id="📰-即時新聞-5-條" tabindex="-1">📰 即時新聞（5 條） <a class="header-anchor" href="#📰-即時新聞-5-條" aria-label="Permalink to &quot;📰 即時新聞（5 條）&quot;">​</a></h2><ol><li><strong>Reuters (2026-05-13)</strong>：川習會將討論 $300 億管理貿易機制，美國農民關注黃豆出口重啟</li><li><strong>Farm Progress (2026-05-12)</strong>：USDA WASDE 26/27 年終庫存 310M bu，低於預期，黃豆升至 2 年高</li><li><strong>AgWeb (2026-05-12)</strong>：USDA 預測美國 將迎來歷來第二大黃豆收成，小麥為 1972 年以來最小</li><li><strong>Farm Progress (2026-05-11)</strong>：川習會若成交易，黃豆期貨可能觸及 $14.80</li><li><strong>Investopedia (2026-05-13)</strong>：PPI 飆升 6%，伊朗戰爭推升化肥與柴油成本</li></ol><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>Yahoo Finance (2026-05-13): ZS=F $1,229.25, ZSK26 $1,221.25</li><li>Farm Progress (2026-05-12): USDA WASDE 26/27 年終庫存 310M bu</li><li>Successful Farming (2026-05-11): 種植進度 49%，五年均值 36%</li><li>Reuters (2026-05-13): 川習會 $300 億管理貿易機制</li><li>AP (2026-05-13): 川普抵達北京，農民關注黃豆出口</li><li>AgWeb (2026-05-12): USDA 預測第二大黃豆收成</li><li>Farm Progress (2026-05-11): 黃豆期貨可能觸及 $14.80</li><li>Investopedia (2026-05-13): PPI 6%，化肥成本上升</li><li>Al Jazeera (2026-05-13): 伊朗戰爭停火「on life support」</li><li>ISW (2026-05-12): 伊朗保留 Hormuz 30 個飛彈基地</li></ol>',33)])])}const b=r(a,[["render",n]]);export{c as __pageData,b as default};
